// { scale, dx, dy } for one step of one drawing id — dx/dy already as
// CSS translate() percentages. [1, 0, 0] if the id or step isn't in the
// table.
export function drawingAlign(id, stepIndex) {
  const [scale, dx, dy] = DRAWING_ALIGN[id]?.[stepIndex] ?? [1, 0, 0]
  return { scale, dx: dx * 100, dy: dy * 100 }
}
